import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            String correct = scanner.next();
            String chef = scanner.next();
            int[] winnings = new int[N + 1];
            for (int i = 0; i <= N; i++) {
                winnings[i] = scanner.nextInt();
            }
            int max_winnings = 0;
            int[] permutation = new int[N];
            for (int i = 0; i < N; i++) {
                permutation[i] = i;
            }
            do {
                int current_winnings = 0;
                for (int i = 0; i < N; i++) {
                    if (correct.charAt(permutation[i]) == chef.charAt(permutation[i])) {
                        current_winnings++;
                    } else {
                        break;
                    }
                }
                max_winnings = Math.max(max_winnings, winnings[current_winnings]);
            } while (nextPermutation(permutation));
            System.out.println(max_winnings);
        }
    }

    public static boolean nextPermutation(int[] permutation) {
        int i = permutation.length - 2;
        while (i >= 0 && permutation[i] >= permutation[i + 1]) {
            i--;
        }
        if (i < 0) {
            return false;
        }
        int j = permutation.length - 1;
        while (j > i && permutation[j] <= permutation[i]) {
            j--;
        }
        swap(permutation, i, j);
        reverse(permutation, i + 1);
        return true;
    }

    public static void swap(int[] permutation, int i, int j) {
        int temp = permutation[i];
        permutation[i] = permutation[j];
        permutation[j] = temp;
    }

    public static void reverse(int[] permutation, int start) {
        int i = start, j = permutation.length - 1;
        while (i < j) {
            swap(permutation, i, j);
            i++;
            j--;
        }
    }
}

