    N = int(input())
    correct = input()
    chef = input()
    winnings = list(map(int, input().split()))
    max_winnings = 0
    permutation = list(range(N))
    while True:
        current_winnings = 0
        for i in range(N):
            if correct[permutation[i]] == chef[permutation[i]]:
                current_winnings += 1
            else:
                break
        max_winnings = max(max_winnings, winnings[current_winnings])
        if not next_permutation(permutation):
            break
    print(max_winnings)

